<?php require 'vendor/autoload.php'; $app = require_once 'bootstrap/app.php'; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $s = App\Models\Soutenance::with('creneau', 'jury.enseignants')->get(); echo $s->count() . ' soutenances found.'; foreach($s as $soutenance) { if(!$soutenance->jury_id || $soutenance->jury->enseignants->where('pivot.role', 'Rapporteur')->count() < 2) { echo 'Incomplete jury for P' . $soutenance->projet_id . ' at ' . $soutenance->creneau->heure_debut . PHP_EOL; } }
